// Ambient module declarations for static asset imports.
// Metro resolves these at bundle time; this file gives TypeScript the types.
declare module '*.png' {
  const value: number;
  export default value;
}
declare module '*.jpg' {
  const value: number;
  export default value;
}
declare module '*.jpeg' {
  const value: number;
  export default value;
}
declare module '*.gif' {
  const value: number;
  export default value;
}
declare module '*.webp' {
  const value: number;
  export default value;
}
declare module '*.svg' {
  const value: number;
  export default value;
}
declare module '*.mp4' {
  const value: number;
  export default value;
}
